-- SCRIPT DE ACTUALIZACIÓN DE PLANTILLAS DINÁMICAS PREMIUM (Fase 28 - FINAL)
-- Soporte para Colores Dinámicos y Logo via CID (Incrustado)

DECLARE @HtmlDinamico NVARCHAR(MAX) = N'<!DOCTYPE html><html><head><meta charset="UTF-8"><style type="text/css">body{margin:0;padding:0;background-color:{COLOR_FONDO}!important;font-family:''Segoe UI'',Tahoma,Geneva,Verdana,sans-serif}table{border-spacing:0;border-collapse:collapse}td{padding:0}</style></head><body style="margin:0;padding:0;background-color:{COLOR_FONDO};"><table role="presentation" width="100%" border="0" cellspacing="0" cellpadding="0" style="background-color:{COLOR_FONDO};width:100%;"><tr><td align="center" style="padding:40px 0;"><table role="presentation" width="600" border="0" cellspacing="0" cellpadding="0" style="background-color:#ffffff;max-width:600px;width:100%;border-radius:12px;overflow:hidden;box-shadow:0 10px 25px rgba(0,0,0,0.1);border:1px solid {BORDER_COLOR};"><thead><tr><td style="background-color:#ffffff;padding:20px 40px;border-bottom:6px solid {COLOR_PRINCIPAL};"><img src="{LOGO_BASE64}" alt="ADL ONE" width="240" style="display:block;width:240px;max-width:240px;height:auto;border:0;"></td></tr></thead><tbody><tr><td style="padding:40px;"><h2 style="margin:0 0 5px 0;color:{COLOR_PRINCIPAL};font-family:Arial,sans-serif;font-size:22px;font-weight:700;">{TITULO_CORREO}</h2><p style="margin:0 0 25px 0;color:#718096;font-family:Arial,sans-serif;font-size:18px;">Notificaci&oacute;n N&ordm;: <strong style="color:{COLOR_PRINCIPAL};font-size:24px;">{CORRELATIVO}</strong></p><table width="100%" border="0" cellspacing="0" cellpadding="0" style="border-top:1px solid #edf2f7;padding-top:20px;"><tr><td width="140" style="padding:8px 0;color:{COLOR_PRINCIPAL};font-weight:bold;font-size:14px;font-family:Arial,sans-serif;white-space:nowrap;">{LABEL_SOLICITANTE}:</td><td style="padding:8px 0;color:#333333;font-size:14px;font-family:Arial,sans-serif;">{USUARIO}</td></tr><tr><td style="padding:8px 0;color:{COLOR_PRINCIPAL};font-weight:bold;font-size:14px;font-family:Arial,sans-serif;">Fecha:</td><td style="padding:8px 0;color:#333333;font-size:14px;font-family:Arial,sans-serif;">{FECHA}</td></tr><tr><td style="padding:8px 0;color:{COLOR_PRINCIPAL};font-weight:bold;font-size:14px;font-family:Arial,sans-serif;">Hora:</td><td style="padding:8px 0;color:#333333;font-size:14px;font-family:Arial,sans-serif;">{HORA}</td></tr></table><div style="margin-top:20px;padding:15px;background-color:{COLOR_FONDO};border-left:4px solid {COLOR_PRINCIPAL};color:#333333;font-size:14px;font-family:Arial,sans-serif;"><strong>{ETIQUETA_OBSERVACION}:</strong><br>{OBSERVACION}</div>{EQUIPOS_DETALLE}</td></tr><tr><td style="padding:25px 40px;background-color:#f8fafc;border-top:1px solid #e2e8f0;"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td align="left" valign="top" style="padding-right:20px;"><strong style="color:#0062a8;font-size:13px;font-family:Arial,sans-serif;display:block;margin-bottom:4px;">ADL Diagnostic Chile SpA</strong><div style="color:#64748b;font-size:11px;line-height:1.4;font-family:Arial,sans-serif;">Laboratorio de Diagn&oacute;stico y Biotecnolog&iacute;a<br>Sector La Vara s/n Camino a Alerce, Puerto Montt<br>Tel/fax: (56 65) 2250292 - 2250234 &ndash; 2250287<br><a href="http://www.adldiagnostic.cl" style="color:#0062a8;text-decoration:none;">www.adldiagnostic.cl</a></div></td><td align="right" valign="top" style="color:#94a3b8;font-size:11px;font-family:Arial,sans-serif;white-space:nowrap;">Sistema de Gesti&oacute;n<br><strong style="color:#0062a8;">Empresarial</strong></td></tr></table></td></tr></tbody></table></td></tr></table></body></html>';

-- Aplicar a todos los eventos relacionados con el Sistema de Solicitudes (URS)
UPDATE mae_evento_notificacion 
SET cuerpo_template_html = @HtmlDinamico,
    asunto_template = N'ADL ONE - Notificación: {CORRELATIVO} - {TIPO_SOLICITUD}'
WHERE codigo_evento IN (
    N'SOLICITUD_NUEVA', 
    N'SOLICITUD_ESTADO_CAMBIO', 
    N'SOLICITUD_COMENTARIO_NUEVO', 
    N'SOLICITUD_DERIVACION'
);

PRINT 'Plantillas de email actualizadas con éxito (Dinámico CID Fase 28).';
